#!/usr/bin/env node
/**
 * Test script for weather-bot fixes
 */

const { spawn } = require('child_process');
const https = require('https');
const http = require('http');

console.log('Testing Weather Bot Fixes...\n');

// Test 1: Weather forecast formatting
console.log('1. Testing weather forecast formatting...');
function getWeatherForecast(type, lat, lon, locationName) {
  return new Promise((resolve, reject) => {
    const scriptPath = '/job/skills/weather-bot/weather.sh';
    const args = [type, lat.toString(), lon.toString(), locationName];

    const child = spawn(scriptPath, args);
    let stdout = '';
    let stderr = '';

    child.stdout.on('data', (data) => {
      stdout += data.toString();
    });

    child.stderr.on('data', (data) => {
      stderr += data.toString();
    });

    child.on('close', (code) => {
      if (code !== 0) {
        reject(new Error(`Script failed: ${stderr}`));
        return;
      }

      try {
        const result = JSON.parse(stdout.trim());
        const message = result.message.replace(/\\n/g, '\n');
        resolve(message);
      } catch (error) {
        reject(error);
      }
    });
  });
}

getWeatherForecast('today', -23.55, -46.70, 'São Paulo')
  .then(message => {
    const hasNewlines = message.includes('\n');
    const hasEmojis = /[🌤️📅☀️💧]/.test(message);
    const hasMarkdown = /\*[^*]+\*/.test(message);
    const lineCount = message.split('\n').length;

    console.log('   ✓ Script executed successfully');
    console.log(`   ✓ Contains newlines: ${hasNewlines} (${lineCount} lines)`);
    console.log(`   ✓ Contains emojis: ${hasEmojis}`);
    console.log(`   ✓ Contains Markdown: ${hasMarkdown}`);
    console.log(`   ✓ Message preview:\n${message.split('\n').slice(0, 5).join('\n')}...\n`);
  })
  .catch(err => {
    console.log('   ✗ Error:', err.message);
  });

// Test 2: IP location
console.log('2. Testing IP location...');
function getIPLocation() {
  return new Promise((resolve, reject) => {
    http.get('http://ip-api.com/json/', (res) => {
      let data = '';
      res.on('data', (chunk) => { data += chunk; });
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          if (json.status === 'success') {
            resolve({
              lat: json.lat,
              lon: json.lon,
              name: `${json.city}, ${json.regionName}`
            });
          } else {
            reject(new Error(json.message || 'Failed'));
          }
        } catch (error) {
          reject(error);
        }
      });
    }).on('error', reject);
  });
}

getIPLocation()
  .then(location => {
    console.log('   ✓ IP location detected');
    console.log(`   ✓ Location: ${location.name}`);
    console.log(`   ✓ Coordinates: ${location.lat}, ${location.lon}\n`);
  })
  .catch(err => {
    console.log('   ✗ Error:', err.message, '\n');
  });

// Test 3: City geocoding
console.log('3. Testing city geocoding...');
function geocodeCity(cityName) {
  return new Promise((resolve, reject) => {
    const encodedName = encodeURIComponent(cityName);
    const url = `https://geocoding-api.open-meteo.com/v1/search?name=${encodedName}&count=1&language=pt&format=json`;

    https.get(url, (res) => {
      let data = '';
      res.on('data', (chunk) => { data += chunk; });
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          if (json.results && json.results.length > 0) {
            const result = json.results[0];
            resolve({
              lat: result.latitude,
              lon: result.longitude,
              name: `${result.name}, ${result.country}`
            });
          } else {
            reject(new Error('City not found'));
          }
        } catch (error) {
          reject(error);
        }
      });
    }).on('error', reject);
  });
}

geocodeCity('Rio de Janeiro')
  .then(location => {
    console.log('   ✓ City geocoding working');
    console.log(`   ✓ Found: ${location.name}`);
    console.log(`   ✓ Coordinates: ${location.lat}, ${location.lon}\n`);
  })
  .catch(err => {
    console.log('   ✗ Error:', err.message, '\n');
  });

// Test 4: Reverse geocoding
console.log('4. Testing reverse geocoding...');
function getLocationName(lat, lon) {
  return new Promise((resolve, reject) => {
    const url = `https://nominatim.openstreetmap.org/reverse?format=json&lat=${lat}&lon=${lon}&zoom=10&accept-language=pt-BR`;

    https.get(url, (res) => {
      let data = '';
      res.on('data', (chunk) => { data += chunk; });
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          if (json.display_name) {
            const parts = json.display_name.split(',');
            if (parts.length >= 2) {
              resolve(parts.slice(0, 2).join(',').trim());
            } else {
              resolve(json.display_name);
            }
          } else if (json.address) {
            const city = json.address.city || json.address.town || json.address.village || json.address.municipality || '';
            const state = json.address.state || '';
            resolve([city, state].filter(Boolean).join(', '));
          } else {
            resolve('Localização desconhecida');
          }
        } catch (error) {
          reject(error);
        }
      });
    }).on('error', reject);
  });
}

getLocationName(-23.55, -46.70)
  .then(name => {
    console.log('   ✓ Reverse geocoding working');
    console.log(`   ✓ Location name: ${name}\n`);
  })
  .catch(err => {
    console.log('   ✗ Error:', err.message, '\n');
  });

// Test 5: Command processing order
console.log('5. Testing command processing order...');
function testCommandProcessing(text, expectedBehavior) {
  const command = text.toLowerCase();
  const isStart = command === '/start';
  const isMenu = command === '/menu' || command === 'menu';
  const isHelp = command === '/help' || command === 'ajuda';
  const isLocation = command === '/location' || command === 'localização';
  const isCommand = text.startsWith('/');

  if (isStart) {
    console.log(`   ✓ Text "${text}" correctly identified as /start command`);
  } else if (isMenu) {
    console.log(`   ✓ Text "${text}" correctly identified as menu command`);
  } else if (isHelp) {
    console.log(`   ✓ Text "${text}" correctly identified as help command`);
  } else if (isLocation) {
    console.log(`   ✓ Text "${text}" correctly identified as location command`);
  } else if (isCommand) {
    console.log(`   ✓ Text "${text}" correctly identified as command`);
  } else {
    console.log(`   ✓ Text "${text}" correctly identified as non-command (city name)`);
  }
}

testCommandProcessing('/start', 'command');
testCommandProcessing('/menu', 'command');
