#!/usr/bin/env node
/**
 * Final comprehensive test for all weather bot fixes
 */

const { spawn } = require('child_process');
const http = require('http');
const https = require('https');

console.log('╔═══════════════════════════════════════════════════════════════╗');
console.log('║   Weather Bot - Final Comprehensive Test                     ║');
console.log('╚═══════════════════════════════════════════════════════════════╝\n');

let passedTests = 0;
let failedTests = 0;

function testResult(testName, passed, message) {
  if (passed) {
    console.log(`✅ ${testName}`);
    if (message) console.log(`   ${message}`);
    passedTests++;
  } else {
    console.log(`❌ ${testName}`);
    if (message) console.log(`   ${message}`);
    failedTests++;
  }
}

// Test 1: Command processing order
console.log('1. Command Processing Order');
console.log('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');

const commandTests = [
  { text: '/start', shouldMatch: true, type: 'start' },
  { text: '/menu', shouldMatch: true, type: 'menu' },
  { text: '/location', shouldMatch: true, type: 'location' },
  { text: '/help', shouldMatch: true, type: 'help' },
  { text: 'Curitiba', shouldMatch: false, type: 'city' },
  { text: '/allow 123', shouldMatch: true, type: 'admin' },
  { text: '/listusers', shouldMatch: true, type: 'admin' },
];

commandTests.forEach(({ text, shouldMatch, type }) => {
  const command = text.toLowerCase();
  const isStart = command === '/start';
  const isMenu = command === '/menu' || command === 'menu';
  const isLocation = command === '/location' || command === 'localização';
  const isHelp = command === '/help' || command === 'ajuda';
  const isAllow = command.startsWith('/allow ');
  const isDisallow = command.startsWith('/disallow ');
  const isListUsers = command === '/listusers' || command === '/listar';
  const isCity = command.startsWith('city:') || command.startsWith('cidade:');
  const isCommand = command.startsWith('/');

  const isRecognizedCommand = isStart || isMenu || isLocation || isHelp ||
                              isAllow || isDisallow || isListUsers || isCity ||
                              isCommand;

  testResult(
    `"${text}" ${isRecognizedCommand ? 'recognized as command' : 'not a command'}`,
    isRecognizedCommand === shouldMatch,
    `Expected: ${shouldMatch ? 'command' : 'non-command'} | Actual: ${isRecognizedCommand ? 'command' : 'non-command'}`
  );
});

console.log('');

// Test 2: Weather forecast formatting
console.log('2. Weather Forecast Formatting');
console.log('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');

function getWeatherForecast(type, lat, lon, locationName) {
  return new Promise((resolve, reject) => {
    const scriptPath = '/job/skills/weather-bot/weather.sh';
    const args = [type, lat.toString(), lon.toString(), locationName];

    const child = spawn(scriptPath, args);
    let stdout = '';
    let stderr = '';

    child.stdout.on('data', (data) => { stdout += data.toString(); });
    child.stderr.on('data', (data) => { stderr += data.toString(); });

    child.on('close', (code) => {
      if (code !== 0) {
        reject(new Error(`Script failed: ${stderr}`));
        return;
      }

      try {
        const result = JSON.parse(stdout.trim());
        const message = result.message.replace(/\\n/g, '\n');
        resolve(message);
      } catch (error) {
        reject(error);
      }
    });
  });
}

getWeatherForecast('tomorrow', -23.55, -46.70, 'São Paulo')
  .then(message => {
    const lines = message.split('\n');
    const hasEmojis = /[🌤️📅☀️💧🌧️🌦️⛅]/.test(message);
    const hasMarkdown = /\*[^*]+\*/.test(message);
    const hasSeparators = /━+/.test(message);
    const hasHourData = /\d{2}h\d{2}.*°C/.test(message);
    const hasRainData = /Chuva: \d+%/.test(message);
    const hasDate = /\d{2}\/\d{2}\/\d{4}/.test(message);

    testResult('Weather forecast generated', lines.length > 10, `Lines: ${lines.length}`);
    testResult('Contains weather emojis', hasEmojis);
    testResult('Contains Markdown formatting', hasMarkdown);
    testResult('Contains visual separators', hasSeparators);
    testResult('Contains hourly data', hasHourData);
    testResult('Contains rain information', hasRainData);
    testResult('Contains date', hasDate);
    testResult('Has proper line breaks', message.includes('\n'));

    console.log('\n   Preview (first 8 lines):');
    lines.slice(0, 8).forEach(line => console.log('   ', line));
    console.log('   ...\n');
  })
  .catch(err => {
    testResult('Weather forecast generated', false, err.message);
    console.log('');
  });

// Test 3: Location methods
console.log('3. Location Methods');
console.log('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');

// Test IP location
function getIPLocation() {
  return new Promise((resolve, reject) => {
    http.get('http://ip-api.com/json/', (res) => {
      let data = '';
      res.on('data', (chunk) => { data += chunk; });
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          if (json.status === 'success') {
            resolve({
              lat: json.lat,
              lon: json.lon,
              name: `${json.city}, ${json.regionName}`
            });
          } else {
            reject(new Error(json.message || 'Failed'));
          }
        } catch (error) {
          reject(error);
        }
      });
    }).on('error', reject);
  });
}

getIPLocation()
  .then(location => {
    testResult('IP location detection working', true, `Found: ${location.name}`);
    testResult('IP coordinates valid', location.lat && location.lon);
  })
  .catch(err => {
    testResult('IP location detection working', false, err.message);
  });

// Test city geocoding
function geocodeCity(cityName) {
  return new Promise((resolve, reject) => {
    const encodedName = encodeURIComponent(cityName);
    const url = `https://geocoding-api.open-meteo.com/v1/search?name=${encodedName}&count=1&language=pt&format=json`;

    https.get(url, (res) => {
      let data = '';
      res.on('data', (chunk) => { data += chunk; });
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          if (json.results && json.results.length > 0) {
            const result = json.results[0];
            resolve({
              lat: result.latitude,
              lon: result.longitude,
              name: `${result.name}, ${result.country}`
            });
          } else {
            reject(new Error('City not found'));
          }
        } catch (error) {
          reject(error);
        }
      });
    }).on('error', reject);
  });
}

geocodeCity('São Paulo')
  .then(location => {
    testResult('City geocoding working', true, `Found: ${location.name}`);
    testResult('City coordinates valid', location.lat && location.lon);
  })
  .catch(err => {
    testResult('City geocoding working', false, err.message);
  });

// Test reverse geocoding
function getLocationName(lat, lon) {
  return new Promise((resolve, reject) => {
    const url = `https://nominatim.openstreetmap.org/reverse?format=json&lat=${lat}&lon=${lon}&zoom=10&accept-language=pt-BR`;

    https.get(url, (res) => {
      let data = '';
      res.on('data', (chunk) => { data += chunk; });
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          if (json.display_name) {
            const parts = json.display_name.split(',');
            if (parts.length >= 2) {
              resolve(parts.slice(0, 2).join(',').trim());
            } else {
              resolve(json.display_name);
            }
          } else if (json.address) {
            const city = json.address.city || json.address.town || json.address.village || json.address.municipality || '';
            const state = json.address.state || '';
            resolve([city, state].filter(Boolean).join(', '));
          } else {
            resolve('Localização desconhecida');
          }
        } catch (error) {
          reject(error);
        }
      });
    }).on('error', reject);
  });
}

getLocationName(-23.55, -46.70)
  .then(name => {
    testResult('Reverse geocoding working', true, `Found: ${name}`);
  })
  .catch(err => {
    testResult('Reverse geocoding working', false, err.message);
  });

setTimeout(() => {
  console.log('\n4. Code Structure Verification');
  console.log('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');

  const fs = require('fs');
  const botCode = fs.readFileSync('/job/triggers/weather-bot.js', 'utf8');

  testResult('Script path is /job/ (not /app/)', botCode.includes("'/job/skills/weather-bot/weather.sh'"));
  testResult('Uses http module for IP location', botCode.includes("const http = require('http')"));
  testResult('Newline replacement in forecast', botCode.includes(".replace(/\\\\n/g, '\\n')"));
  testResult('Commands processed before pending input',
    botCode.indexOf('switch (command)') < botCode.indexOf('getAndClearPendingInput'));

  console.log('\n╔═══════════════════════════════════════════════════════════════╗');
  console.log('║   Test Summary                                               ║');
  console.log('╚═══════════════════════════════════════════════════════════════╝');
  console.log(`✅ Passed: ${passedTests}`);
  console.log(`❌ Failed: ${failedTests}`);
  console.log('');

  if (failedTests === 0) {
    console.log('╔═══════════════════════════════════════════════════════════════╗');
    console.log('║   🎉 All tests passed! Ready for Telegram testing! 🎉        ║');
    console.log('╚═══════════════════════════════════════════════════════════════╝\n');
  } else {
    console.log('⚠️  Some tests failed. Please review the errors above.\n');
  }

  process.exit(failedTests > 0 ? 1 : 0);
}, 3000);
